#include <iostream>
#include <vector>
#include <memory> // For std::unique_ptr
// Assuming Animal, Dog, Cat classes are defined in the solution code

int main() {
    // Using std::vector of std::unique_ptr for safe and efficient memory management
    std::vector<std::unique_ptr<Animal>> animals;

    animals.push_back(std::make_unique<Dog>());
    animals.push_back(std::make_unique<Cat>());
    animals.push_back(std::make_unique<Animal>()); // Also demonstrate base class sound

    // Iterate and call makeSound polymorphically
    for (const auto& animal : animals) {
        animal->makeSound();
    }
    // Destructors (including derived ones) are called automatically
    // when unique_ptr objects go out of scope, thanks to the virtual destructor in Animal.
    std::cout << "All animals have made their sounds and are now out of scope.\n";

    return 0;
}
